import{_ as e,o as d,c as o,a2 as a}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"调度模型","description":"","frontmatter":{},"headers":[],"relativePath":"guide/schedule.md","filePath":"guide/schedule.md","lastUpdated":1783223243000}'),c={name:"guide/schedule.md"};function s(r,t,i,l,n,h){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="调度模型" tabindex="-1">调度模型 <a class="header-anchor" href="#调度模型" aria-label="Permalink to &quot;调度模型&quot;">​</a></h1><p><code>config.json</code> 里所有调度都用同一个对象表达：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;schedule&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;every&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;ISO8601 时长&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;HH:MM&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span></code></pre></div><ul><li><strong><code>every</code></strong> —— ISO8601 时长，表示&quot;每隔多久&quot;。</li><li><strong><code>at</code></strong> —— 可选，<code>HH:MM</code>（24 小时制，补零），表示一天中的执行时刻。<strong>仅当周期 ≥ 1 天时有意义</strong>。</li></ul><p>守护进程 <code>timer_daemon</code> 直接读取 <code>config.json</code> 并在内存中换算成调度表，没有任何中间派生文件，也不需要你接触 cron 表达式。</p><h2 id="every-的取值规则" tabindex="-1"><code>every</code> 的取值规则 <a class="header-anchor" href="#every-的取值规则" aria-label="Permalink to &quot;`every` 的取值规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>含义</th><th><code>every</code> 写法</th><th>是否需要 <code>at</code></th></tr></thead><tbody><tr><td>每 N 分钟</td><td><code>PT2M</code>（每 2 分钟）</td><td>否</td></tr><tr><td>每 N 小时</td><td><code>PT4H</code>（每 4 小时）</td><td>否</td></tr><tr><td>每 N 天</td><td><code>P1D</code> / <code>P3D</code></td><td><strong>是</strong>（指定几点执行）</td></tr><tr><td>每 N 周</td><td><code>P1W</code> / <code>P2W</code></td><td><strong>是</strong></td></tr></tbody></table><p>格式固定：</p><ul><li><code>PT&lt;正整数&gt;M</code> / <code>PT&lt;正整数&gt;H</code> —— 时间分量（分 / 时）。</li><li><code>P&lt;正整数&gt;D</code> / <code>P&lt;正整数&gt;W</code> —— 日期分量（天 / 周）。</li></ul><p>数字必须是 <strong>≥ 1 的正整数</strong>。</p><h2 id="两类调度" tabindex="-1">两类调度 <a class="header-anchor" href="#两类调度" aria-label="Permalink to &quot;两类调度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>字段</th><th>特点</th></tr></thead><tbody><tr><td><strong>频率类</strong></td><td><code>app_clean.detect_schedule</code>、<code>suppress.detect_schedule</code>、<code>gc.schedule</code></td><td>只用分钟 / 小时间隔，<strong>不写 <code>at</code></strong></td></tr><tr><td><strong>定时类</strong></td><td><code>app_clean.other.schedule</code>、<code>empty_folder.schedule</code></td><td>既有间隔（每几天 / 几周），又有时刻 <code>at</code></td></tr></tbody></table><h2 id="对照示例" tabindex="-1">对照示例 <a class="header-anchor" href="#对照示例" aria-label="Permalink to &quot;对照示例&quot;">​</a></h2><table tabindex="0"><thead><tr><th><code>every</code> / <code>at</code></th><th>含义</th></tr></thead><tbody><tr><td><code>PT2M</code></td><td>每 2 分钟</td></tr><tr><td><code>PT4H</code></td><td>每 4 小时</td></tr><tr><td><code>P1D</code> + <code>03:00</code></td><td>每天 03:00</td></tr><tr><td><code>P3D</code> + <code>03:00</code></td><td>每 3 天的 03:00</td></tr><tr><td><code>P1W</code> + <code>04:00</code></td><td>每周一次，04:00</td></tr></tbody></table><h2 id="关键约束" tabindex="-1">关键约束 <a class="header-anchor" href="#关键约束" aria-label="Permalink to &quot;关键约束&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">务必遵守</p><ol><li><strong>频率类不要写 <code>at</code></strong>（写了会被忽略）；<strong>定时类（天 / 周）必须写 <code>at</code></strong>，否则默认按 <code>00:00</code> 执行。</li><li><strong><code>every</code> 必须是 ≥ 1 的正整数</strong>。解析失败时该任务会被跳过，等于该功能不执行。</li><li><strong>写完即生效，无需重启</strong> —— 请用原子写入（先写临时文件再 <code>mv</code> 覆盖）。</li></ol></div><h2 id="多天周期的底层机制" tabindex="-1">多天周期的底层机制 <a class="header-anchor" href="#多天周期的底层机制" aria-label="Permalink to &quot;多天周期的底层机制&quot;">​</a></h2><p>cron 表达式无法精确表达&quot;每 N 天&quot;，因此模块对周期 ≥ 1 天的任务采用<strong>时间戳门控</strong>：守护进程每天在 <code>at</code> 时刻触发，执行前检查 <code>cron/state</code> 里记录的上次运行时间，距上次不满 N 天则跳过。<code>cron/state</code> 由守护进程自动维护，你只需写好 <code>config.json</code> 里的 <code>schedule</code> 对象即可。</p>',18)])])}const u=e(c,[["render",s]]);export{g as __pageData,u as default};
